import React, { Component } from "react";
import PageHelmet from "../component/common/Helmet";
import Breadcrumb from "../elements/common/Breadcrumb";
import { FiCast , FiLayers , FiUsers , FiMonitor ,FiChevronUp } from "react-icons/fi";
import ScrollToTop from 'react-scroll-up';
import Header from "../component/header/Header";
import Footer from "../component/footer/Footer";
import ReactGA from "react-ga4"



const ServiceList = [
    {
        icon: <FiCast />,
        title: 'Business Stratagy',
        description: 'I throw myself down among the tall grass by the stream as I lie close to the earth.'
    },
    {
        icon: <FiLayers />,
        title: 'Website Development',
        description: 'I throw myself down among the tall grass by the stream as I lie close to the earth.'
    },
    {
        icon: <FiUsers />,
        title: 'Marketing & Reporting',
        description: 'I throw myself down among the tall grass by the stream as I lie close to the earth.'
    },
    {
        icon: <FiMonitor />,
        title: 'Mobile App Development',
        description: 'I throw myself down among the tall grass by the stream as I lie close to the earth.'
    },
    {
        icon: <FiCast />,
        title: 'Website Development',
        description: 'I throw myself down among the tall grass by the stream as I lie close to the earth.'
    },
    {
        icon: <FiMonitor />,
        title: 'Marketing & Reporting',
        description: 'I throw myself down among the tall grass by the stream as I lie close to the earth.'
    },
]

const MarketingServiceList = [
    {
        icon: <FiCast />,
        title: 'SEO',
        description: 'I throw myself down among the tall grass by the stream as I lie close to the earth.'
    },
    {
        icon: <FiLayers />,
        title: 'Social Media Marketing',
        description: 'I throw myself down among the tall grass by the stream as I lie close to the earth.'
    },
    {
        icon: <FiUsers />,
        title: 'Search Engine Marketing',
        description: 'I throw myself down among the tall grass by the stream as I lie close to the earth.'
    }
]

const CreativeAgencyServiceList = [

    {
        icon: <FiMonitor />,
        title: 'Content Creation- Photography Videograhpy',
        description: 'I throw myself down among the tall grass by the stream as I lie close to the earth.'
    }
]

const ItStrategyServiceList = [
    {
        icon: <FiCast />,
        title: 'SEO',
        description: 'I throw myself down among the tall grass by the stream as I lie close to the earth.'
    },
    {
        icon: <FiLayers />,
        title: 'Social Media Marketing',
        description: 'I throw myself down among the tall grass by the stream as I lie close to the earth.'
    },
    {
        icon: <FiUsers />,
        title: 'Search Engine Marketing',
        description: 'I throw myself down among the tall grass by the stream as I lie close to the earth.'
    },
    {
        icon: <FiMonitor />,
        title: 'Content Creation- Photography Videograhpy',
        description: 'I throw myself down among the tall grass by the stream as I lie close to the earth.'
    }
]

const DevelopmentServiceList = [
    {
        icon: <FiCast />,
        title: 'Mobile App',
        description: 'Turning your app ideas into reality with precision and innovation.'
    },
    {
        icon: <FiLayers />,
        title: 'Web App',
        description: 'Crafting web solutions that make your business stand out online.'
    },
    {
        icon: <FiUsers />,
        title: 'Software Automation',
        description: 'Simplify, streamline, and enhance with automation.'
    },
    {
        icon: <FiMonitor />,
        title: 'ETL & Data Transfer',
        description: 'Seamless data flow: ETL and data transfer expertise.'
    }
]

class Service extends Component{
    render(){

        ReactGA.send({
            hitType:"pageview",
            page:"/",
            title: "Service"
        });

        return(
            <React.Fragment>
                <PageHelmet pageTitle='Service' />
                <Header headertransparent="header--transparent" colorblack="color--black" logoname="logo.png" />

                {/* Start Breadcrump Area */}
                <Breadcrumb title={'Service'}   />
                {/* End Breadcrump Area */}

                  {/* Start Service Area */}
                  <div className="service-area creative-service-wrapper pt--90 pb--120 bg_color--1">
                    <div className="container">
                        <div className="row">
                            <div className="col-lg-12">
                                <div className="section-title text-center mb--30">
                                    <h2>Development</h2>
                                    <p>There are many variations of passages of Lorem Ipsum available, <br /> but the majority have suffered alteration.</p>
                                </div>
                            </div>
                        </div>
                        <div className="row creative-service">
                            {DevelopmentServiceList.map( (val , i) => (
                                <div className="col-xl-4 col-lg-4 col-md-6 col-sm-6 col-12" key={i}>
                                    <a className="text-center" href="/service-details">
                                        <div className="service service__style--2">
                                            <div className="icon">
                                                {val.icon}
                                            </div>
                                            <div className="content">
                                                <h3 className="title">{val.title}</h3>
                                                <p>{val.description}</p>
